mapper.select:
SELECT

FROM vip_subscription
WHERE tenant_id = #{tenantId}
  AND id = #{id}

SELECT

FROM vip_subscription
WHERE tenant_id = #{tenantId}
  AND toc_user_id = #{tocUserId}
ORDER BY id DESC

SELECT

FROM vip_subscription
WHERE tenant_id = #{tenantId}
  AND order_id = #{orderId}
ORDER BY id DESC

mapper.update:
UPDATE vip_subscription
SET toc_user_id = #{tocUserId},
    plan_id = #{planId},
    order_id = #{orderId},
    subscription_status = #{subscriptionStatus},
    start_at = #{startAt},
    end_at = #{endAt}
WHERE tenant_id = #{tenantId}
  AND id = #{id}

mapper.delete:
DELETE
FROM vip_subscription
WHERE tenant_id = #{tenantId}
  AND id = #{id}
